def get_matrix_and_jobs(current_sequence: list, time_matrix: np.ndarray,
                         m: int, n: int) -> tuple:
    import numpy as np

    new_matrix = time_matrix.copy()

    # Compute completion times
    C = np.zeros((n, m))
    for i, job in enumerate(current_sequence):
        for j in range(m):
            if i == 0 and j == 0:
                C[i, j] = time_matrix[job, j]
            elif i == 0:
                C[i, j] = C[i, j-1] + time_matrix[job, j]
            elif j == 0:
                C[i, j] = C[i-1, j] + time_matrix[job, j]
            else:
                C[i, j] = max(C[i-1, j], C[i, j-1]) + time_matrix[job, j]

    # Compute idle time each job causes on each machine
    idle_impact = np.zeros(n)
    for i, job in enumerate(current_sequence):
        for j in range(1, m):
            if i == 0:
                idle = C[i, j-1] - C[i, j] + time_matrix[job, j]
            else:
                idle = max(0, C[i-1, j] - C[i, j-1])
            idle_impact[job] += idle

    # Determine threshold: mean idle impact
    threshold = np.mean(idle_impact) if n > 0 else 0
    bottleneck_jobs = np.where(idle_impact > threshold)[0]

    # Apply deterministic penalty (multiply by 1.3) to bottleneck jobs on all machines
    for job in bottleneck_jobs:
        new_matrix[job, :] *= 1.3

    # Select jobs to perturb: bottleneck jobs sorted by idle impact (descending)
    if len(bottleneck_jobs) > 0:
        sorted_bottleneck = bottleneck_jobs[np.argsort(-idle_impact[bottleneck_jobs])]
        perturb_jobs = sorted_bottleneck[:5].tolist()
        if len(perturb_jobs) < 2:
            for i in range(n):
                if len(perturb_jobs) >= 2:
                    break
                if i not in perturb_jobs:
                    perturb_jobs.append(i)
    else:
        perturb_jobs = list(range(min(5, n)))

    perturb_jobs = perturb_jobs[:5]
    if len(perturb_jobs) < 2:
        for i in range(n):
            if len(perturb_jobs) >= 2:
                break
            if i not in perturb_jobs:
                perturb_jobs.append(i)

    return new_matrix, perturb_jobs
